/* 十神 */
function tenGod(dm,tgt){
  if(!WX_G[dm]||!WX_G[tgt])return'—';
  const d=WX_G[dm],t=WX_G[tgt],s=YY_G[dm]===YY_G[tgt];
  if(d===t)return s?'比肩':'劫財';
  if(SHENG[d]===t)return s?'食神':'傷官';
  if(KE[d]===t)return s?'偏財':'正財';
  if(KE[t]===d)return s?'七殺':'正官';
  if(SHENG[t]===d)return s?'偏印':'正印';
  return'—';
}
// 十神白話標籤（給一般用戶看的）
function godLabel(god){
  return{'比肩':'夥伴','劫財':'競爭者','食神':'才華','傷官':'衝勁','偏財':'意外財','正財':'穩定財','七殺':'外部壓力','正官':'規範約束','偏印':'靈感','正印':'貴人庇護'}[god]||god;
}

/* 十二長生 */
const CHANG_SHENG_ORDER=['長生','沐浴','冠帶','臨官','帝旺','衰','病','死','墓','絕','胎','養'];
const CS_START={甲:DZ.indexOf('亥'),丙:DZ.indexOf('寅'),戊:DZ.indexOf('寅'),庚:DZ.indexOf('巳'),壬:DZ.indexOf('申'),
                乙:DZ.indexOf('午'),丁:DZ.indexOf('酉'),己:DZ.indexOf('酉'),辛:DZ.indexOf('子'),癸:DZ.indexOf('卯')};
function changSheng(dm,zhi){
  const start=CS_START[dm]; if(start===undefined)return'—';
  const zhiIdx=DZ.indexOf(zhi); if(zhiIdx<0)return'—';
  const isYang=YY_G[dm]==='陽';
  let diff=isYang?(zhiIdx-start+12)%12:(start-zhiIdx+12)%12;
  return CHANG_SHENG_ORDER[diff];
}

/* ═══════════════════════════════════════════════════════════════
   神煞 (完整版 — 30+ 種吉凶神煞)
   包含：吉神 16 種 + 凶煞 18 種 = 34 種
   ═══════════════════════════════════════════════════════════════ */
function getShenSha(pillars){
  const ss=[];
  const yZ=pillars.year.zhi, yG=pillars.year.gan;
  const mZ=pillars.month.zhi, mG=pillars.month.gan;
  const dG=pillars.day.gan, dZ=pillars.day.zhi;
  const hZ=pillars.hour.zhi, hG=pillars.hour.gan;
  const allZhi=[yZ,mZ,dZ,hZ];
  const otherZhi=[yZ,mZ,hZ]; // 除日支外
  const fourZhi=[mZ,dZ,hZ];  // 除年支外（年支為查表基準時）

  // ═══ 輔助：地支索引 ═══
  const DZ_LIST=['子','丑','寅','卯','辰','巳','午','未','申','酉','戌','亥'];
  const dzIdx=z=>DZ_LIST.indexOf(z);

  // ════════════════════════════════════════
  //  【一】吉 神 (16 種)
  // ════════════════════════════════════════

  // 1. 天乙貴人 — 以日干查，見於年/月/時支
  const TIYI={甲:['丑','未'],戊:['丑','未'],庚:['丑','未'],丙:['亥','酉'],丁:['亥','酉'],
              乙:['子','申'],己:['子','申'],壬:['卯','巳'],癸:['卯','巳'],辛:['午','寅']};
  if(TIYI[dG]) otherZhi.forEach(z=>{if(TIYI[dG].includes(z))ss.push('天乙貴人')});

  // 2. 天德貴人 — 以月支查，見於四柱天干或地支
  const TIANDE_GAN={寅:'丁',卯:'申',辰:'壬',巳:'辛',午:'亥',未:'甲',申:'癸',酉:'寅',戌:'丙',亥:'乙',子:'巳',丑:'庚'};
  if(TIANDE_GAN[mZ]){
    const tg=TIANDE_GAN[mZ];
    if([yG,mG,dG,hG].includes(tg)||allZhi.includes(tg)) ss.push('天德貴人');
  }

  // 3. 月德貴人 — 以月支查，見於四柱天干
  const YUEDE={寅:'丙',午:'丙',戌:'丙', 申:'壬',子:'壬',辰:'壬', 亥:'甲',卯:'甲',未:'甲', 巳:'庚',酉:'庚',丑:'庚'};
  if(YUEDE[mZ]&&[yG,mG,dG,hG].includes(YUEDE[mZ])) ss.push('月德貴人');

  // 4. 天德合 — 天德貴人所合之干
  const TIANDE_HE={丁:'壬',申:'巳',壬:'丁',辛:'丙',亥:'寅',甲:'己',癸:'戊',寅:'亥',丙:'辛',乙:'庚',巳:'申',庚:'乙'};
  if(TIANDE_GAN[mZ]){
    const heGan=TIANDE_HE[TIANDE_GAN[mZ]];
    if(heGan&&[yG,mG,dG,hG].includes(heGan)) ss.push('天德合');
  }

  // 5. 月德合 — 月德貴人所合之干
  const YUEDE_HE={丙:'辛',壬:'丁',甲:'己',庚:'乙'};
  if(YUEDE[mZ]){
    const heGan=YUEDE_HE[YUEDE[mZ]];
    if(heGan&&[yG,mG,dG,hG].includes(heGan)) ss.push('月德合');
  }

  // 6. 文昌 — 以日干查，見於年/月/時支
  const WC={甲:'巳',乙:'午',丙:'申',丁:'酉',戊:'申',己:'酉',庚:'亥',辛:'子',壬:'寅',癸:'卯'};
  if(WC[dG]) otherZhi.forEach(z=>{if(z===WC[dG])ss.push('文昌')});

  // 7. 學堂 — 以日干長生之地查（日干五行長生所在地支見於四柱）
  const XUETANG={甲:'亥',乙:'午',丙:'寅',丁:'酉',戊:'寅',己:'酉',庚:'巳',辛:'子',壬:'申',癸:'卯'};
  if(XUETANG[dG]&&allZhi.includes(XUETANG[dG])) ss.push('學堂');

  // 8. 詞館 — 以日干查
  const CIGUAN={甲:'寅',乙:'卯',丙:'巳',丁:'午',戊:'巳',己:'午',庚:'申',辛:'酉',壬:'亥',癸:'子'};
  if(CIGUAN[dG]&&allZhi.includes(CIGUAN[dG])) ss.push('詞館');

  // 9. 國印貴人 — 以年干查，見於四柱地支
  const GUOYIN={甲:'戌',乙:'亥',丙:'丑',丁:'寅',戊:'丑',己:'寅',庚:'辰',辛:'巳',壬:'未',癸:'申'};
  if(GUOYIN[yG]&&allZhi.includes(GUOYIN[yG])) ss.push('國印貴人');

  // 10. 福星貴人 — 以年干查，見於四柱地支
  const FUXING={甲:'寅',乙:'卯',丙:'巳',丁:'午',戊:'巳',己:'午',庚:'申',辛:'酉',壬:'亥',癸:'子'};  // 臨官之位
  if(FUXING[yG]&&[mZ,dZ,hZ].includes(FUXING[yG])) ss.push('福星貴人');

  // 11. 三奇貴人 — 天上三奇(甲戊庚)、地下三奇(乙丙丁)、人中三奇(壬癸辛)
  const gans=[yG,mG,dG,hG];
  const gStr=gans.join('');
  if(/甲.*戊.*庚/.test(gStr)) ss.push('天上三奇');
  if(/乙.*丙.*丁/.test(gStr)) ss.push('地下三奇');
  if(/壬.*癸.*辛/.test(gStr)) ss.push('人中三奇');

  // 12. 金輿 — 以日干查，見於四柱地支
  const JINYU={甲:'辰',乙:'巳',丙:'未',丁:'申',戊:'未',己:'申',庚:'戌',辛:'亥',壬:'丑',癸:'寅'};
  if(JINYU[dG]&&allZhi.includes(JINYU[dG])) ss.push('金輿');

  // 13. 天廚 — 以日干查，見於四柱地支（食神建祿之位）
  const TIANCHU={甲:'巳',乙:'午',丙:'申',丁:'酉',戊:'申',己:'酉',庚:'亥',辛:'子',壬:'寅',癸:'卯'};
  if(TIANCHU[dG]&&allZhi.includes(TIANCHU[dG])) ss.push('天廚');

  // 14. 將星 — 以年支查三合局中位，見於月/日/時支
  const JIANGXING={子:'子',丑:'酉',寅:'午',卯:'卯',辰:'子',巳:'酉',午:'午',未:'卯',申:'子',酉:'酉',戌:'午',亥:'卯'};
  if(JIANGXING[yZ]) fourZhi.forEach(z=>{if(z===JIANGXING[yZ])ss.push('將星')});

  // 15. 驛馬 — 以年支查，見於月/日/時支
  const YM={子:'寅',丑:'亥',寅:'申',卯:'巳',辰:'寅',巳:'亥',午:'申',未:'巳',申:'寅',酉:'亥',戌:'申',亥:'巳'};
  if(YM[yZ]) fourZhi.forEach(z=>{if(z===YM[yZ])ss.push('驛馬')});

  // 16. 桃花（咸池）— 以年支查，見於月/日/時支
  const TH_MAP={子:'酉',丑:'午',寅:'卯',卯:'子',辰:'酉',巳:'午',午:'卯',未:'子',申:'酉',酉:'午',戌:'卯',亥:'子'};
  if(TH_MAP[yZ]) fourZhi.forEach(z=>{if(z===TH_MAP[yZ])ss.push('桃花')});

  // ════════════════════════════════════════
  //  【二】凶 煞 (18 種)
  // ════════════════════════════════════════

  // 17. 華蓋 — 以年支查，見於月/日/時支（孤高之星，亦可吉用）
  const HG_MAP={子:'辰',丑:'丑',寅:'戌',卯:'未',辰:'辰',巳:'丑',午:'戌',未:'未',申:'辰',酉:'丑',戌:'戌',亥:'未'};
  if(HG_MAP[yZ]) fourZhi.forEach(z=>{if(z===HG_MAP[yZ])ss.push('華蓋')});

  // 18. 羊刃 — 以日干查帝旺之地，見於四柱地支
  const YANGREN={甲:'卯',乙:'寅',丙:'午',丁:'巳',戊:'午',己:'巳',庚:'酉',辛:'申',壬:'子',癸:'亥'};
  if(YANGREN[dG]&&allZhi.includes(YANGREN[dG])) ss.push('羊刃');

  // 19. 劫煞 — 以年支查（三合局前一位取對沖）
  const JIESHA={子:'巳',丑:'寅',寅:'亥',卯:'申',辰:'巳',巳:'寅',午:'亥',未:'申',申:'巳',酉:'寅',戌:'亥',亥:'申'};
  if(JIESHA[yZ]) fourZhi.forEach(z=>{if(z===JIESHA[yZ])ss.push('劫煞')});

  // 20. 亡神 — 以年支查
  const WANGSHEN={子:'亥',丑:'申',寅:'巳',卯:'寅',辰:'亥',巳:'申',午:'巳',未:'寅',申:'亥',酉:'申',戌:'巳',亥:'寅'};
  if(WANGSHEN[yZ]) fourZhi.forEach(z=>{if(z===WANGSHEN[yZ])ss.push('亡神')});

  // 21. 災煞 — 以年支查
  const ZAISHA={子:'午',丑:'卯',寅:'子',卯:'酉',辰:'午',巳:'卯',午:'子',未:'酉',申:'午',酉:'卯',戌:'子',亥:'酉'};
  if(ZAISHA[yZ]) fourZhi.forEach(z=>{if(z===ZAISHA[yZ])ss.push('災煞')});

  // 22. 六厄 — 以年支查
  const LIUE={子:'巳',丑:'午',寅:'未',卯:'申',辰:'酉',巳:'戌',午:'亥',未:'子',申:'丑',酉:'寅',戌:'卯',亥:'辰'};
  if(LIUE[yZ]) fourZhi.forEach(z=>{if(z===LIUE[yZ])ss.push('六厄')});

  // 23. 孤辰 — 以年支查，見於其他地支
  const GUCHEN={子:'寅',丑:'寅',寅:'巳',卯:'巳',辰:'巳',巳:'申',午:'申',未:'申',申:'亥',酉:'亥',戌:'亥',亥:'寅'};
  if(GUCHEN[yZ]&&[mZ,dZ,hZ].includes(GUCHEN[yZ])) ss.push('孤辰');

  // 24. 寡宿 — 以年支查，見於其他地支
  const GUASU={子:'戌',丑:'戌',寅:'丑',卯:'丑',辰:'丑',巳:'辰',午:'辰',未:'辰',申:'未',酉:'未',戌:'未',亥:'戌'};
  if(GUASU[yZ]&&[mZ,dZ,hZ].includes(GUASU[yZ])) ss.push('寡宿');

  // 25. 空亡 — 以日柱查旬空（日干支所在旬的最後兩個地支）
  const TG_LIST=['甲','乙','丙','丁','戊','己','庚','辛','壬','癸'];
  const tgIdx=TG_LIST.indexOf(dG);
  const diIdx=dzIdx(dZ);
  // 日干支的干支差 = (diIdx - tgIdx + 12) % 12 → 旬首位置
  const xunStart=(diIdx-tgIdx+12)%12;
  // 空亡 = 旬首前兩位 = (xunStart+10)%12 和 (xunStart+11)%12
  const kongWang1=DZ_LIST[(xunStart+10)%12];
  const kongWang2=DZ_LIST[(xunStart+11)%12];
  if([yZ,mZ,hZ].some(z=>z===kongWang1||z===kongWang2)) ss.push('空亡');

  // 26. 血刃 — 以日支查（日支前兩位），見於其他地支
  const XUEREN_ZHI=DZ_LIST[(dzIdx(dZ)+2)%12];
  if([yZ,mZ,hZ].includes(XUEREN_ZHI)) ss.push('血刃');

  // 27. 紅艷煞 — 以日干查，見於四柱地支
  const HONGYAN={甲:'午',乙:'午',丙:'寅',丁:'未',戊:'辰',己:'辰',庚:'戌',辛:'酉',壬:'子',癸:'申'};
  if(HONGYAN[dG]&&allZhi.includes(HONGYAN[dG])) ss.push('紅艷煞');

  // 28. 陰陽差錯 — 特定日柱組合
  const YCCC=['丙子','丁丑','戊寅','辛卯','壬辰','癸巳','丙午','丁未','戊申','辛酉','壬戌','癸亥'];
  if(YCCC.includes(dG+dZ)) ss.push('陰陽差錯');

  // 29. 十惡大敗 — 特定日柱於特定年份
  const SEDB={甲辰:['甲','乙'],乙巳:['甲','乙'],丙申:['丙','丁'],丁亥:['丙','丁'],
              戊戌:['戊','己'],己丑:['戊','己'],庚辰:['庚','辛'],辛巳:['庚','辛'],
              壬申:['壬','癸'],癸亥:['壬','癸']};
  const dayPillar=dG+dZ;
  if(SEDB[dayPillar]&&SEDB[dayPillar].includes(yG)) ss.push('十惡大敗');

  // 30. 白虎煞 — 以年支查
  const BAIHU={子:'申',丑:'酉',寅:'戌',卯:'亥',辰:'子',巳:'丑',午:'寅',未:'卯',申:'辰',酉:'巳',戌:'午',亥:'未'};  // 年支+8
  if(BAIHU[yZ]&&fourZhi.includes(BAIHU[yZ])) ss.push('白虎');

  // 31. 天狗 — 以年支查（年支+10，與弔客同位，但語義不同：天狗主損傷產厄）
  const TIANGOU={子:'戌',丑:'亥',寅:'子',卯:'丑',辰:'寅',巳:'卯',午:'辰',未:'巳',申:'午',酉:'未',戌:'申',亥:'酉'}; // 年支+10
  if(TIANGOU[yZ]&&fourZhi.includes(TIANGOU[yZ])) ss.push('天狗');

  // 32. 喪門 — 以年支查（太歲前二辰 = 年支+2）
  const SANGMEN={子:'寅',丑:'卯',寅:'辰',卯:'巳',辰:'午',巳:'未',午:'申',未:'酉',申:'戌',酉:'亥',戌:'子',亥:'丑'};
  if(SANGMEN[yZ]&&fourZhi.includes(SANGMEN[yZ])) ss.push('喪門');

  // 33. 弔客 — 以年支查（太歲後二辰 = 年支-2 = +10）
  const DIAOKE={子:'戌',丑:'亥',寅:'子',卯:'丑',辰:'寅',巳:'卯',午:'辰',未:'巳',申:'午',酉:'未',戌:'申',亥:'酉'};
  if(DIAOKE[yZ]&&fourZhi.includes(DIAOKE[yZ])) ss.push('弔客');

  // 34. 勾絞煞 — 勾煞(年支+1) + 絞煞(年支-1)
  const gouSha=DZ_LIST[(dzIdx(yZ)+1)%12];
  const jiaoSha=DZ_LIST[(dzIdx(yZ)+11)%12];
  if(fourZhi.includes(gouSha)) ss.push('勾煞');
  if(fourZhi.includes(jiaoSha)) ss.push('絞煞');

  // ════════════════════════════════════════
  //  【三】流年神煞（紅鸞天喜 — 用於感情分析）
  // ════════════════════════════════════════

  // 35. 紅鸞 — 以年支查（子→卯, 逆推）
  const HONGLUAN={子:'卯',丑:'寅',寅:'丑',卯:'子',辰:'亥',巳:'戌',午:'酉',未:'申',申:'未',酉:'午',戌:'巳',亥:'辰'};
  if(HONGLUAN[yZ]&&fourZhi.includes(HONGLUAN[yZ])) ss.push('紅鸞');

  // 36. 天喜 — 紅鸞對沖
  const TIANXI={子:'酉',丑:'申',寅:'未',卯:'午',辰:'巳',巳:'辰',午:'卯',未:'寅',申:'丑',酉:'子',戌:'亥',亥:'戌'};
  if(TIANXI[yZ]&&fourZhi.includes(TIANXI[yZ])) ss.push('天喜');

  return[...new Set(ss)];
}

