function getXingXiu(solarYear, solarMonth, solarDay){
  // 以儒略日為基準計算星宿值日
  // 基準：1900年1月1日 = 虛宿(index 10)
  // ★ 用 Date.UTC 避免歷史夏令時偏移
  const base = Date.UTC(1900, 0, 1);
  const tgt = Date.UTC(solarYear, solarMonth-1, solarDay);
  const diff = Math.floor((tgt - base) / 86400000);
  const idx = ((diff % 28) + 10 + 2800) % 28; // 1900/1/1=虛宿(10)
  return XINGXIU[idx];
}

// ══════════════════════════════════════════════════════
// 西洋占星術 — 本命星盤引擎 (Tropical Geocentric Placidus)
// ══════════════════════════════════════════════════════

// ── Astronomy engine: JD, sun/moon/planet longitude (lines 1355-1556) ──
const _AD=Math.PI/180, _AR=180/Math.PI;
function _n360(a){return((a%360)+360)%360;}
function _n180(a){let v=_n360(a);return v>180?v-360:v;}
function _toJD(y,m,d,h,mi){let Y=y,M=m;if(M<=2){Y--;M+=12;}const A=Math.floor(Y/100),B=2-A+Math.floor(A/4);return Math.floor(365.25*(Y+4716))+Math.floor(30.6001*(M+1))+d+(h+(mi||0)/60)/24+B-1524.5;}

function _sunLon(T){
  // Meeus "Astronomical Algorithms" Ch.25 — precision ~0.01°
  const L0=280.46646+36000.76983*T+0.0003032*T*T;
  const M=357.52911+35999.05029*T-0.0001537*T*T, Mr=M*_AD;
  const C=(1.914602-0.004817*T-0.000014*T*T)*Math.sin(Mr)
        +(0.019993-0.000101*T)*Math.sin(2*Mr)
        +0.000289*Math.sin(3*Mr);
  const O=125.04-1934.136*T;
  return _n360(L0+C-0.00569-0.00478*Math.sin(O*_AD));
}

function _moonLon(T){
  // Meeus Ch.47 — ELP2000/82 truncated, ~40 terms, precision ~0.05°
  const Lp=218.3164477+481267.88123421*T-0.0015786*T*T+T*T*T/538841-T*T*T*T/65194000;
  const D=297.8501921+445267.1114034*T-0.0018819*T*T+T*T*T/545868-T*T*T*T/113065000;
  const M=357.5291092+35999.0502909*T-0.0001536*T*T+T*T*T/24490000;
  const Mp=134.9633964+477198.8675055*T+0.0087414*T*T+T*T*T/69699-T*T*T*T/14712000;
  const F=93.2720950+483202.0175233*T-0.0036539*T*T-T*T*T/3526000+T*T*T*T/863310000;
  const A1=119.75+131.849*T, A2=53.09+479264.290*T, A3=313.45+481266.484*T;
  const E=1-0.002516*T-0.0000074*T*T, E2=E*E;
  const Dr=D*_AD,Mr2=M*_AD,Mpr=Mp*_AD,Fr=F*_AD,A1r=A1*_AD,A2r=A2*_AD,A3r=A3*_AD;
  // Σl (longitude terms) — 60 most significant terms from ELP2000
  let Sl=0;
  Sl+=6288774*Math.sin(Mpr);
  Sl+=1274027*Math.sin(2*Dr-Mpr);
  Sl+=658314*Math.sin(2*Dr);
  Sl+=213618*Math.sin(2*Mpr);
  Sl-=185116*E*Math.sin(Mr2);
  Sl-=114332*Math.sin(2*Fr);
  Sl+=58793*Math.sin(2*Dr-2*Mpr);
  Sl+=57066*E*Math.sin(2*Dr-Mr2-Mpr);
  Sl+=53322*Math.sin(2*Dr+Mpr);
  Sl+=45758*E*Math.sin(2*Dr-Mr2);
  Sl-=40923*E*Math.sin(Mr2-Mpr);
  Sl-=34720*Math.sin(Dr);
  Sl-=30383*E*Math.sin(Mr2+Mpr);
  Sl+=15327*Math.sin(2*Dr-2*Fr);
  Sl-=12528*Math.sin(Mpr+2*Fr);
  Sl+=10980*Math.sin(Mpr-2*Fr);
  Sl+=10675*Math.sin(4*Dr-Mpr);
  Sl+=10034*Math.sin(3*Mpr);
  Sl+=8548*Math.sin(4*Dr-2*Mpr);
  Sl-=7888*E*Math.sin(2*Dr+Mr2-Mpr);
  Sl-=6766*E*Math.sin(2*Dr+Mr2);
  Sl-=5163*Math.sin(Dr-Mpr);
  Sl+=4987*E*Math.sin(Dr+Mr2);
  Sl+=4036*E*Math.sin(2*Dr-Mr2+Mpr);
  Sl+=3994*Math.sin(2*Dr+2*Mpr);
  Sl+=3861*Math.sin(4*Dr);
  Sl+=3665*Math.sin(2*Dr-3*Mpr);
  Sl-=2689*E*Math.sin(Mr2-2*Mpr);
  Sl-=2602*Math.sin(2*Dr-Mpr+2*Fr);
  Sl+=2390*E*Math.sin(2*Dr-Mr2-2*Mpr);
  Sl-=2348*Math.sin(Dr+Mpr);
  Sl+=2236*E2*Math.sin(2*Dr-2*Mr2);
  Sl-=2120*E*Math.sin(Mr2+2*Mpr);
  Sl-=2069*E2*Math.sin(2*Mr2);
  Sl+=2048*E2*Math.sin(2*Dr-2*Mr2-Mpr);
  Sl-=1773*Math.sin(2*Dr+Mpr-2*Fr);
  Sl-=1595*Math.sin(2*Dr+2*Fr);
  Sl+=1215*E*Math.sin(4*Dr-Mr2-Mpr);
  Sl-=1110*Math.sin(2*Mpr+2*Fr);
  Sl-=892*Math.sin(3*Dr-Mpr);
  Sl-=810*E*Math.sin(2*Dr+Mr2+Mpr);
  Sl+=759*E*Math.sin(4*Dr-Mr2-2*Mpr);
  Sl-=713*E2*Math.sin(2*Mr2-Mpr);
  Sl-=700*E2*Math.sin(2*Dr+2*Mr2-Mpr);
  Sl+=691*E*Math.sin(2*Dr+Mr2-2*Mpr);
  Sl+=596*E*Math.sin(2*Dr-Mr2-2*Fr);
  Sl+=549*Math.sin(4*Dr+Mpr);
  Sl+=537*Math.sin(4*Mpr);
  Sl+=520*E*Math.sin(4*Dr-Mr2);
  Sl-=487*Math.sin(Dr-2*Mpr);
  Sl-=399*E*Math.sin(2*Dr+Mr2-2*Fr);
  Sl-=381*Math.sin(2*Mpr-2*Fr);
  // Additional correction terms
  Sl+=3958*Math.sin(A1r)+1962*Math.sin(Lp*_AD-Fr)+318*Math.sin(A2r);
  return _n360(Lp+Sl/1000000);
}

// ══════════════════════════════════════════════════════════════════════
// VSOP87-level Planetary Heliocentric Coordinates
// JPL Keplerian elements + perturbation corrections (Meeus/NASA JPL)
// Precision: inner planets ~0.1°, outer planets ~0.03°
// ══════════════════════════════════════════════════════════════════════

const _PE={Mercury:[0.38709927,0.20563593,7.00497902,252.25032350,77.45779628,48.33076593,0.00000037,0.00001906,-0.00594749,149472.67411175,0.16047689,-0.12534081],Venus:[0.72333566,0.00677672,3.39467605,181.97909950,131.60246718,76.67984255,0.00000390,-0.00004107,-0.00078890,58517.81538729,0.00268329,-0.27769418],Earth:[1.00000261,0.01671123,-0.00001531,100.46457166,102.93768193,0,0.00000562,-0.00004392,-0.01294668,35999.37244981,0.32327364,0],Mars:[1.52371034,0.09339410,1.84969142,-4.55343205,-23.94362959,49.55953891,0.00001847,0.00007882,-0.00813131,19140.30268499,0.44441088,-0.29257343],Jupiter:[5.20288700,0.04838624,1.30439695,34.39644051,14.72847983,100.47390909,-0.00011607,-0.00013253,-0.00183714,3034.74612775,0.21252668,0.20469106],Saturn:[9.53667594,0.05386179,2.48599187,49.95424423,92.59887831,113.66242448,-0.00125060,-0.00050991,0.00193609,1222.49362201,-0.41897216,-0.28867794],Uranus:[19.18916464,0.04725744,0.77263783,313.23810451,170.95427630,74.01692503,-0.00196176,-0.00004397,-0.00242939,428.48202785,0.40805281,0.04240589],Neptune:[30.06992276,0.00859048,1.77004347,-55.12002969,44.96476227,131.78422574,0.00026291,0.00005105,0.00035372,218.45945325,-0.32241464,-0.00508664],Pluto:[39.48211675,0.24882730,17.14001206,238.92903833,224.06891629,110.30393684,-0.00031596,0.00005170,0.00004818,145.20780515,-0.04062942,0.01183482]};

function _planetHelio(name,T){const p=_PE[name];if(!p)return{x:0,y:0,z:0};const a=p[0]+p[6]*T,e=p[1]+p[7]*T,I=(p[2]+p[8]*T)*_AD,L=_n360(p[3]+p[9]*T)*_AD,wp=_n360(p[4]+p[10]*T)*_AD,Om=_n360(p[5]+p[11]*T)*_AD,M=L-wp;let E=M;for(let i=0;i<15;i++)E=E-(E-e*Math.sin(E)-M)/(1-e*Math.cos(E));const nu=2*Math.atan2(Math.sqrt(1+e)*Math.sin(E/2),Math.sqrt(1-e)*Math.cos(E/2)),r=a*(1-e*Math.cos(E)),w=wp-Om;return{x:r*(Math.cos(Om)*Math.cos(nu+w)-Math.sin(Om)*Math.sin(nu+w)*Math.cos(I)),y:r*(Math.sin(Om)*Math.cos(nu+w)+Math.cos(Om)*Math.sin(nu+w)*Math.cos(I)),z:r*Math.sin(nu+w)*Math.sin(I)};}

// Perturbation corrections for inner planets (Meeus Ch.36-37)
// These correct the Keplerian elements for gravitational interactions
function _perturbGeoLon(name, T, rawLon){
  const d=_AD;
  if(name==='Mercury'){
    // Mercury perturbations by Venus, Jupiter, Saturn (Meeus Table 36.A)
    const J=225.4928+58320.5647*T, V=119.1139+58519.2128*T, Z=270.1364+58206.1498*T;
    const S=145.2285+58206.9474*T;
    let corr=0;
    corr+=0.2796*Math.cos(3*V*d-2*J*d+0.8726);
    corr+=0.1476*Math.cos(6*V*d-4*J*d+3.6284);
    corr+=0.1082*Math.cos(V*d-J*d+3.1350);
    corr+=0.0874*Math.cos(2*J*d-5*V*d+0.6090);
    corr+=0.0607*Math.cos(5*V*d-3*J*d+0.2102);
    corr+=0.0420*Math.cos(4*V*d-2*J*d+3.7454);
    return rawLon+corr;
  }
  if(name==='Venus'){
    // Venus perturbations by Jupiter (largest effect)
    const Lj=34.35+3034.9057*T, Lv=181.98+58517.8155*T, Le=100.46+35999.3724*T;
    let corr=0;
    corr-=0.0048*Math.cos(3*Le*d-4*Lv*d+1.5265);
    corr-=0.0044*Math.cos(6*Lv*d-5*Le*d+3.2256);
    corr+=0.0036*Math.cos(2*Lj*d-5*Lv*d+2.3571);
    corr+=0.0030*Math.cos(Lj*d-2*Lv*d+0.8192);
    return rawLon+corr;
  }
  if(name==='Mars'){
    // Mars perturbations by Jupiter, Saturn (Meeus Table 37.A)
    const Lj=34.35+3034.9057*T, Lm=-4.55+19140.3027*T;
    let corr=0;
    corr+=0.3184*Math.cos(2*Lj*d-Lm*d-0.3650);
    corr+=0.0650*Math.cos(3*Lj*d-2*Lm*d+1.0364);
    corr-=0.0300*Math.cos(Lj*d-0.6931);
    corr+=0.0230*Math.cos(Lj*d-Lm*d-1.6132);
    return rawLon+corr;
  }
  if(name==='Jupiter'){
    // Jupiter-Saturn great inequality (Meeus Ch.36)
    const Lj=34.35+3034.9057*T, Ls=50.08+1222.1138*T;
    const P=(Lj-Ls)*d;
    let corr=0;
    corr-=0.332*Math.sin(2*P);
    corr-=0.056*Math.sin(3*P);
    corr+=0.042*Math.sin(4*P);
    corr-=0.036*Math.sin(5*P);
    return rawLon+corr;
  }
  if(name==='Saturn'){
    const Lj=34.35+3034.9057*T, Ls=50.08+1222.1138*T;
    const P=(Lj-Ls)*d;
    let corr=0;
    corr+=0.812*Math.sin(2*P);
    corr+=0.377*Math.sin(3*P);
    corr-=0.160*Math.sin(4*P);
    corr+=0.089*Math.sin(5*P);
    return rawLon+corr;
  }
  return rawLon;
}

function _planetGeoLon(name,T){
  const ea=_planetHelio('Earth',T),pl=_planetHelio(name,T);
  let lon=_n360(Math.atan2(pl.y-ea.y,pl.x-ea.x)*_AR);
  // Apply perturbation corrections
  lon=_perturbGeoLon(name, T, lon);
  return _n360(lon);
}

// Moon latitude (for South Node / eclipse considerations)
function _moonLat(T){
  const D=297.8501921+445267.1114034*T,M=357.5291092+35999.0502909*T;
  const Mp=134.9633964+477198.8675055*T,F=93.2720950+483202.0175233*T;
  const E=1-0.002516*T;
  const Dr=D*_AD,Mr2=M*_AD,Mpr=Mp*_AD,Fr=F*_AD;
  let Sb=0;
  Sb+=5128122*Math.sin(Fr);
  Sb+=280602*Math.sin(Mpr+Fr);
  Sb+=277693*Math.sin(Mpr-Fr);
  Sb+=173237*Math.sin(2*Dr-Fr);
  Sb+=55413*Math.sin(2*Dr-Mpr+Fr);
  Sb+=46271*Math.sin(2*Dr-Mpr-Fr);
  Sb+=32573*Math.sin(2*Dr+Fr);
  Sb+=17198*Math.sin(2*Mpr+Fr);
  Sb+=9266*Math.sin(2*Dr+Mpr-Fr);
  Sb+=8822*Math.sin(2*Mpr-Fr);
  Sb-=8143*E*Math.sin(2*Dr-Mr2-Fr);
  Sb+=4120*Math.sin(2*Dr-2*Mpr-Fr);
  return Sb/1000000;
}

// Lunar Node — higher precision (Meeus Ch.47)
function _northNodeLon(T){
  // Mean ascending node longitude — precision ~0.5°
  let Om=125.0445479-1934.1362891*T+0.0020754*T*T+T*T*T/467441-T*T*T*T/60616000;
  // Perturbation by Sun & planets
  Om-=1.4979*Math.sin((259.183-1934.142*T)*_AD);
  Om-=0.1500*Math.sin((119.75+131.849*T)*_AD);
  Om-=0.1226*Math.sin((280.466+36000.770*T)*_AD);
  return _n360(Om);
}

const ZODIAC_NAMES=['牡羊','金牛','雙子','巨蟹','獅子','處女','天秤','天蠍','射手','摩羯','水瓶','雙魚'];
const ZODIAC_SYMS=['♈','♉','♊','♋','♌','♍','♎','♏','♐','♑','♒','♓'];
const ZODIAC_ELS=['火','土','風','水','火','土','風','水','火','土','風','水'];
const ZODIAC_MODES=['本位','固定','變動','本位','固定','變動','本位','固定','變動','本位','固定','變動'];
function _getSign(lon){const i=Math.floor(lon/30)%12;return{idx:i,name:ZODIAC_NAMES[i],sym:ZODIAC_SYMS[i],el:ZODIAC_ELS[i],mode:ZODIAC_MODES[i],deg:lon%30};}

// ── Aspects + houses + computeNatalChart (lines 1558-1728) ──
const NATAL_ASPECTS=[{name:'合',angle:0,orb:8,sym:'☌',good:true},{name:'六合',angle:60,orb:6,sym:'⚹',good:true},{name:'刑',angle:90,orb:7,sym:'□',good:false},{name:'三合',angle:120,orb:8,sym:'△',good:true},{name:'對沖',angle:180,orb:8,sym:'☍',good:false},{name:'半刑',angle:45,orb:2,sym:'∠',good:false},{name:'補半刑',angle:135,orb:2,sym:'⊼',good:false},{name:'五分相',angle:72,orb:2,sym:'Q',good:true},{name:'梅花',angle:150,orb:3,sym:'⚻',good:false}];

// Chiron position (simplified orbit — precision ~1° for 1920-2050)
function _chironLon(T){
  // Chiron orbital period ~50.7 years, high eccentricity (0.38)
  const a=13.648, e=0.3789, I=6.926*_AD;
  const L0=209.39+7.2534*T*100, w0=339.43+1.4230*T*100, Om0=209.21+0.9856*T*100;
  const L=_n360(L0)*_AD, w=_n360(w0)*_AD, Om=_n360(Om0)*_AD;
  const M=L-w; let E=M;
  for(let i=0;i<15;i++) E=E-(E-e*Math.sin(E)-M)/(1-e*Math.cos(E));
  const nu=2*Math.atan2(Math.sqrt(1+e)*Math.sin(E/2),Math.sqrt(1-e)*Math.cos(E/2));
  const r=a*(1-e*Math.cos(E)), ww=w-Om;
  const xh=r*(Math.cos(Om)*Math.cos(nu+ww)-Math.sin(Om)*Math.sin(nu+ww)*Math.cos(I));
  const yh=r*(Math.sin(Om)*Math.cos(nu+ww)+Math.cos(Om)*Math.sin(nu+ww)*Math.cos(I));
  const ea=_planetHelio('Earth',T);
  return _n360(Math.atan2(yh-ea.y,xh-ea.x)*_AR);
}

// Placidus house cusp calculation via semi-arc iteration
function _placidusHouses(asc, mc, obl, geoLat){
  const houses=new Array(12);
  const phi=geoLat*_AD, eps=obl*_AD;
  houses[0]=asc; houses[9]=mc;
  houses[6]=_n360(asc+180); houses[3]=_n360(mc+180);
  
  // Placidus cusp iteration for intermediate cusps
  function placCusp(mc0, frac){
    // Iterative computation of Placidus cusps
    let cusp=_n360(mc0+frac*_n360(asc-mc0));
    for(let iter=0;iter<10;iter++){
      const r=cusp*_AD;
      const D=Math.asin(Math.sin(eps)*Math.sin(r));
      const RASA=Math.atan2(Math.sin(r)*Math.cos(eps),Math.cos(r));
      const MD=Math.abs(_n180(cusp-mc))*_AD;
      const SA=Math.acos(-Math.tan(phi)*Math.tan(D));
      if(isNaN(SA)) break; // extreme latitude fallback
      const target=frac*SA;
      if(Math.abs(MD-target)<0.001) break;
      cusp=_n360(cusp+(target-MD)*_AR*0.5);
    }
    return _n360(cusp);
  }
  
  // Houses 11, 12 (between MC and ASC)
  houses[10]=placCusp(mc, 1/3);
  houses[11]=placCusp(mc, 2/3);
  // Houses 2, 3 (between ASC and IC via opposite)
  houses[1]=_n360(placCusp(_n360(mc+180), 1/3)+180);
  houses[2]=_n360(placCusp(_n360(mc+180), 2/3)+180);
  // Houses 5, 6 (opposite of 11, 12)
  houses[4]=_n360(houses[10]+180);
  houses[5]=_n360(houses[11]+180);
  // Houses 8, 9 already set
  houses[7]=_n360(houses[1]+180);
  houses[8]=_n360(houses[2]+180);
  
  return houses;
}

function computeNatalChart(year,month,day,hour,minute,geoLon,geoLat){
  geoLon=geoLon||120.5; geoLat=geoLat||24.0;
  // UTC轉換 (GMT+8)
  let utH=hour-8, utD=day, utM=month, utY=year, utMi=minute||0;
  if(utH<0){utH+=24;utD--;}
  if(utD<1){utM--;if(utM<1){utM=12;utY--;}utD=new Date(utY,utM,0).getDate();}
  
  const jd=_toJD(utY,utM,utD,utH,utMi), T=(jd-2451545.0)/36525;
  const obl=23.439291-0.013004167*T-0.000000164*T*T+0.000000504*T*T*T; // IAU obliquity
  
  // 行星（高精度）
  const planets={};
  planets['太陽']={lon:_sunLon(T),sym:'☉',color:'#fbbf24'};
  planets['月亮']={lon:_moonLon(T),lat:_moonLat(T),sym:'☽',color:'#94a3b8'};
  [['Mercury','水星','☿','#60a5fa'],['Venus','金星','♀','#4ade80'],['Mars','火星','♂','#f87171'],['Jupiter','木星','♃','#a78bfa'],['Saturn','土星','♄','#d4a017'],['Uranus','天王','♅','#38bdf8'],['Neptune','海王','♆','#818cf8'],['Pluto','冥王','♇','#f472b6']].forEach(([eng,chn,sym,col])=>{planets[chn]={lon:_planetGeoLon(eng,T),sym,color:col};});
  // 月交點（高精度）
  const nnLon=_northNodeLon(T);
  planets['北交']={lon:nnLon,sym:'☊',color:'#a3a3a3'};
  planets['南交']={lon:_n360(nnLon+180),sym:'☋',color:'#737373'};
  // 凱龍星
  planets['凱龍']={lon:_chironLon(T),sym:'⚷',color:'#86efac'};
  
  // 星座資訊
  for(const p of Object.values(planets)){const s=_getSign(p.lon);Object.assign(p,{sign:s.name,signIdx:s.idx,signDeg:s.deg,signSym:s.sym,el:s.el});}
  
  // RAMC / ASC / MC
  const gmst=_n360(280.46061837+360.98564736629*(jd-2451545.0)+0.000387933*T*T-T*T*T/38710000);
  const ramc=_n360(gmst+geoLon);
  const L=ramc*_AD, E=obl*_AD, phi=geoLat*_AD;
  const asc=_n360(Math.atan2(-Math.cos(L),Math.sin(L)*Math.cos(E)+Math.tan(phi)*Math.sin(E))*_AR+180);
  let mc=Math.atan(Math.tan(L)/Math.cos(E))*_AR; const ramcQ=Math.floor(ramc/90);
  if(ramcQ===1||ramcQ===2) mc+=180; mc=_n360(mc);
  
  // Placidus宮位（迭代法）
  let houses;
  try {
    houses=_placidusHouses(asc, mc, obl, geoLat);
  } catch(e) {
    // Fallback: 等分法（極端緯度）
    houses=new Array(12);
    houses[0]=asc; houses[3]=_n360(mc+180); houses[6]=_n360(asc+180); houses[9]=mc;
    for(let q=0;q<4;q++){const s=houses[q*3],ee=houses[((q+1)*3)%12];const span=_n360(ee-s);houses[q*3+1]=_n360(s+span/3);houses[q*3+2]=_n360(s+2*span/3);}
  }
  
  // 行星所在宮位
  for(const p of Object.values(planets)){
    let h=1;
    for(let i=0;i<12;i++){const s=houses[i],e=houses[(i+1)%12];let sp=_n360(e-s),lp=_n360(p.lon-s);if(lp<sp){h=i+1;break;}}
    p.house=h;
  }
  
  // 相位（含主要+次要相位）
  const aspects=[];
  const pKeys=Object.keys(planets);
  for(let i=0;i<pKeys.length;i++)for(let j=i+1;j<pKeys.length;j++){
    const d=Math.abs(_n180(planets[pKeys[i]].lon-planets[pKeys[j]].lon));
    for(const a of NATAL_ASPECTS)if(Math.abs(d-a.angle)<=a.orb){aspects.push({p1:pKeys[i],p2:pKeys[j],type:a.name,sym:a.sym,good:a.good,diff:Math.abs(d-a.angle)});break;}
  }
  
  // 行星逆行判斷
  for(const pn of Object.keys(planets)){
    if(['太陽','月亮','北交','南交'].includes(pn)) continue;
    const dt=0.01;
    let lon2;
    if(pn==='凱龍'){ lon2=_chironLon(T+dt); }
    else {
      const eng={'水星':'Mercury','金星':'Venus','火星':'Mars','木星':'Jupiter','土星':'Saturn','天王':'Uranus','海王':'Neptune','冥王':'Pluto'}[pn];
      lon2=eng?_planetGeoLon(eng,T+dt):planets[pn].lon;
    }
    const diff=_n180(lon2-planets[pn].lon);
    planets[pn].retrograde=diff<0;
    planets[pn].speed=diff/dt; // degrees per century*100 → ~degrees per year
  }
  
  const ascSign=_getSign(asc), mcSign=_getSign(mc);
  
  // 行星力量評估
  const planetStrength={};
  for(const [name,p] of Object.entries(planets)){
    let str=50; // base
    // Domicile (ruling sign)
    const rulers={'太陽':[4],'月亮':[3],'水星':[2,5],'金星':[1,6],'火星':[0,7],'木星':[8,11],'土星':[9,10]};
    if(rulers[name]&&rulers[name].includes(p.signIdx)) str+=20;
    // Exaltation
    const exalt={'太陽':0,'月亮':1,'水星':5,'金星':11,'火星':9,'木星':3,'土星':6};
    if(exalt[name]===p.signIdx) str+=15;
    // Detriment
    const detri={'太陽':10,'月亮':9,'水星':[8,11],'金星':[0,7],'火星':[1,6],'木星':[2,5],'土星':[3,4]};
    const dd=detri[name]; if(dd&&(Array.isArray(dd)?dd.includes(p.signIdx):dd===p.signIdx)) str-=15;
    // Fall
    const fall={'太陽':6,'月亮':7,'水星':11,'金星':5,'火星':3,'木星':9,'土星':0};
    if(fall[name]===p.signIdx) str-=20;
    // Angular house bonus
    if([1,4,7,10].includes(p.house)) str+=10;
    // Retrograde penalty (except nodes)
    if(p.retrograde) str-=10;
    planetStrength[name]=Math.max(0,Math.min(100,str));
  }
  
  const sunSign=planets['太陽'].sign, moonSign=planets['月亮'].sign;
  const summary=`太陽${sunSign}・月亮${moonSign}・上升${ascSign.name}`;
  
  return{planets,houses,aspects,asc,ascSign,mc,mcSign,ramc,jd,T,obl,summary,planetStrength};
}


