// 🕉️ JYOTISH BATCH 3: TRANSITS, KARAKAS, CROSS-VALIDATION
// ══════════════════════════════════════════════════════════════════════

// ── Current Transit Positions (simplified ephemeris for slow planets) ──
function jyCurrentTransits() {
  var now = new Date();
  var y = now.getFullYear(), m = now.getMonth() + 1, d = now.getDate();
  var h = now.getHours();
  var utH = h - 8; if (utH < 0) { utH += 24; d--; }
  if (d < 1) { m--; if (m < 1) { m = 12; y--; } d = new Date(y, m, 0).getDate(); }
  var jd = _toJD(y, m, d, utH, 0);
  var T = (jd - 2451545.0) / 36525.0;
  // v52: Ayanamsa mode-aware
  var _ayanMode2 = (typeof window !== 'undefined' && window.JY_AYANAMSA_MODE) ? window.JY_AYANAMSA_MODE : 'lahiri';
  var ayan = (typeof jyGetAyanamsa === 'function') ? jyGetAyanamsa(jd, _ayanMode2) : jyLahiriAyanamsa(jd);
  
  var transits = {};
  // Sun
  transits.Sun = { sidLon: jyToSidereal(_sunLon(T), ayan) };
  // Moon
  transits.Moon = { sidLon: jyToSidereal(_moonLon(T), ayan) };
  // Major planets via existing functions
  ['Mercury','Venus','Mars','Jupiter','Saturn'].forEach(function(p) {
    try {
      var tropLon = _planetGeoLon(p === 'Mercury' ? 'Mercury' : p === 'Venus' ? 'Venus' : p === 'Mars' ? 'Mars' : p === 'Jupiter' ? 'Jupiter' : 'Saturn', T);
      transits[p] = { sidLon: jyToSidereal(tropLon, ayan) };
    } catch(e) { transits[p] = { sidLon: 0 }; }
  });
  // Rahu/Ketu
  var rahuTrop = _n360(125.0446 - 1934.1363 * T);
  transits.Rahu = { sidLon: jyToSidereal(rahuTrop, ayan) };
  transits.Ketu = { sidLon: _n360(transits.Rahu.sidLon + 180) };
  
  // Add rashi info
  Object.keys(transits).forEach(function(p) {
    var r = jyGetRashi(transits[p].sidLon);
    transits[p].rashiIdx = r.idx;
    transits[p].rashi = r.rashi;
    transits[p].degInSign = r.deg;
    var n = jyGetNakshatra(transits[p].sidLon);
    transits[p].naksIdx = n.idx;
    transits[p].nakshatra = n.nakshatra;
  });
  
  return transits;
}

// ── Transit Impact Analysis ──
// How current transits affect natal chart
function jyTransitImpact(natal, transits, lagnaIdx) {
  var impacts = [];
  
  var slowPlanets = ['Jupiter','Saturn','Rahu','Ketu'];
  
  slowPlanets.forEach(function(tp) {
    var tr = transits[tp];
    if (!tr) return;
    var transitBhava = ((tr.rashiIdx - lagnaIdx + 12) % 12) + 1;
    
    // Check what natal planets are being aspected
    var aspectedPlanets = [];
    Object.keys(natal).forEach(function(np) {
      var npl = natal[np];
      if (!npl || !npl.sidLon) return;
      var diff = Math.abs(_n180(tr.sidLon - npl.sidLon));
      // Conjunction (0°), Opposition (180°), Trine (120°), Square (90°)
      if (diff <= 8) aspectedPlanets.push({planet:np, aspect:'合', orb:diff});
      else if (Math.abs(diff - 180) <= 8) aspectedPlanets.push({planet:np, aspect:'對沖', orb:Math.abs(diff-180)});
      else if (Math.abs(diff - 120) <= 8) aspectedPlanets.push({planet:np, aspect:'三合', orb:Math.abs(diff-120)});
      else if (Math.abs(diff - 90) <= 8) aspectedPlanets.push({planet:np, aspect:'刑', orb:Math.abs(diff-90)});
    });
    
    var nature = JY_PLANETS[tp] ? JY_PLANETS[tp].nature : 'neutral';
    var isPositiveHouse = [1,2,5,9,10,11].includes(transitBhava);
    var isNegativeHouse = [6,8,12].includes(transitBhava);
    
    var impact = {
      planet: tp,
      zh: JY_PLANETS[tp].zh,
      transitRashi: tr.rashi.zh,
      transitBhava: transitBhava,
      bhavaZh: JY_BHAVA[transitBhava - 1].zh,
      aspectedPlanets: aspectedPlanets,
      tone: ''
    };
    
    // Jupiter transit = expansion
    if (tp === 'Jupiter') {
      if (isPositiveHouse) impact.tone = '木星行運第' + transitBhava + '宮，帶來擴張與好運，把握機會';
      else if (isNegativeHouse) impact.tone = '木星行運第' + transitBhava + '宮，保護力較弱但不至於壞事';
      else impact.tone = '木星行運第' + transitBhava + '宮，成長機會中等';
    }
    // Saturn transit = restriction/lessons
    else if (tp === 'Saturn') {
      if (isPositiveHouse) impact.tone = '土星行運第' + transitBhava + '宮，雖有壓力但能帶來穩固的成果';
      else if (isNegativeHouse) impact.tone = '土星行運第' + transitBhava + '宮，考驗期，需要耐心和紀律';
      else impact.tone = '土星行運第' + transitBhava + '宮，責任感增加但可控';
    }
    // Rahu = obsession/unconventional
    else if (tp === 'Rahu') {
      if (transitBhava <= 6) impact.tone = '羅睺行運第' + transitBhava + '宮，' + JY_BHAVA[transitBhava-1].domain + '方面有非傳統的發展';
      else impact.tone = '羅睺行運第' + transitBhava + '宮，' + JY_BHAVA[transitBhava-1].domain + '方面需留意幻象';
    }
    // Ketu = detachment/spirituality
    else if (tp === 'Ketu') {
      impact.tone = '計都行運第' + transitBhava + '宮，' + JY_BHAVA[transitBhava-1].domain + '方面可能需要放下某些執著';
    }
    
    // Aspects on natal planets
    if (aspectedPlanets.length > 0) {
      aspectedPlanets.forEach(function(ap) {
        if (tp === 'Jupiter' && (ap.aspect === '合' || ap.aspect === '三合')) {
          impact.tone += '；木星' + ap.aspect + '本命' + JY_PLANETS[ap.planet].zh + '，帶來祝福與擴展';
        } else if (tp === 'Saturn' && (ap.aspect === '合' || ap.aspect === '刑' || ap.aspect === '對沖')) {
          impact.tone += '；土星' + ap.aspect + '本命' + JY_PLANETS[ap.planet].zh + '，帶來考驗但也帶來成熟';
        }
      });
    }
    
    impacts.push(impact);
  });
  
  return impacts;
}

// ── Atmakaraka (Soul Significator) ──
// Planet with highest degree in any sign (excluding Rahu/Ketu in some traditions)
function jyCalcAtmakaraka(planets) {
  var maxDeg = -1;
  var ak = null;
  var karakas = [];
  
  // Collect degrees for 7 planets + Rahu
  var candidates = ['Sun','Moon','Mars','Mercury','Jupiter','Venus','Saturn','Rahu'];
  var karakaNames = ['靈魂主星','心意之星','兄弟之星','母親之星','子女之星','知識之星','配偶之星','父親之星'];
  
  var sorted = candidates.map(function(p) {
    return { planet: p, deg: planets[p] ? planets[p].degInSign : 0 };
  }).sort(function(a, b) { return b.deg - a.deg; });
  
  for (var i = 0; i < Math.min(sorted.length, 8); i++) {
    karakas.push({
      role: karakaNames[i],
      planet: sorted[i].planet,
      zh: JY_PLANETS[sorted[i].planet].zh,
      deg: Math.round(sorted[i].deg * 100) / 100
    });
  }
  
  return {
    atmakaraka: sorted[0] ? sorted[0].planet : null,
    atmakarakaZh: sorted[0] ? JY_PLANETS[sorted[0].planet].zh : '?',
    karakas: karakas
  };
}

// ── D2 (Hora) Chart — Wealth ──
// Odd signs: 0-15° = Sun (Leo), 15-30° = Moon (Cancer)
// Even signs: 0-15° = Moon (Cancer), 15-30° = Sun (Leo)
function jyHora(sidLon) {
  var signIdx = Math.floor(sidLon / 30) % 12;
  var deg = sidLon % 30;
  var isOdd = (signIdx % 2 === 0); // 0-indexed: 0=Aries(odd), 1=Taurus(even)
  if (isOdd) {
    return deg < 15 ? { lord: 'Sun', rashi: JY_RASHI[4], wealth: '自力型財富' } : { lord: 'Moon', rashi: JY_RASHI[3], wealth: '被動型財富' };
  } else {
    return deg < 15 ? { lord: 'Moon', rashi: JY_RASHI[3], wealth: '被動型財富' } : { lord: 'Sun', rashi: JY_RASHI[4], wealth: '自力型財富' };
  }
}

// ── D7 (Saptamsa) Chart — Children ──
// For odd signs: count from same sign in 7 parts
// For even signs: count from 7th sign
function jySaptamsa(sidLon) {
  var signIdx = Math.floor(sidLon / 30) % 12;
  var deg = sidLon % 30;
  var part = Math.floor(deg / (30 / 7)); // 0-6
  if (part > 6) part = 6;
  var startSign;
  if (signIdx % 2 === 0) { startSign = signIdx; } // Odd signs: from same
  else { startSign = (signIdx + 6) % 12; } // Even signs: from 7th
  return { signIdx: (startSign + part) % 12, rashi: JY_RASHI[(startSign + part) % 12], part: part + 1 };
}

// ── D4 (Chaturthamsa) Chart — Property/Fortune ──
// Divide each sign into 4 parts of 7.5° each
function jyChaturthamsa(sidLon) {
  var signIdx = Math.floor(sidLon / 30) % 12;
  var deg = sidLon % 30;
  var part = Math.floor(deg / 7.5); // 0-3
  if (part > 3) part = 3;
  var d4SignIdx = (signIdx * 4 + signIdx + part) % 12; // simplified
  // Proper: Aries→Ari,Can,Lib,Cap; Taurus→Tau,Leo,Sco,Aqu; etc.
  var base = signIdx * 3;
  d4SignIdx = (signIdx + part * 3) % 12;
  return { signIdx: d4SignIdx, rashi: JY_RASHI[d4SignIdx], part: part + 1 };
}


// ── jyCrossValidation + remedies (lines 3712-4050) ──
// ══════════════════════════════════════════════════════════════════════
// 🔗 CROSS-VALIDATION: Jyotish × Bazi × Ziwei
// Three independent timing systems compared
// ══════════════════════════════════════════════════════════════════════
function jyCrossValidation(jy, bazi, ziwei, type) {
  if (!jy) return null;
  
  var signals = [];
  var agreements = 0, disagreements = 0;
  
  // ── 1. Timing Comparison: Jyotish Dasha vs Bazi Dayun ──
  if (jy.currentMD && bazi && bazi.dayun) {
    var curBaziDy = bazi.dayun.find(function(d) { return d.isCurrent; });
    var jyDashaGood = false, baziDyGood = false;
    
    // Jyotish: Is current Dasha lord well-placed?
    var mdLord = jy.currentMD.lord;
    if (jy.planets[mdLord]) {
      var mdDig = jy.planets[mdLord].dignity;
      jyDashaGood = (mdDig === 'exalted' || mdDig === 'own' || mdDig === 'moola' || mdDig === 'friend');
    }
    
    // Bazi: Is current Dayun positive?
    if (curBaziDy) {
      baziDyGood = (curBaziDy.level && (curBaziDy.level.includes('吉') || curBaziDy.level.includes('旺')));
    }
    
    if (jyDashaGood && baziDyGood) {
      agreements++;
      signals.push({
        type: 'timing_agree_pos',
        zh: '✅ 時間軸一致看好：吠陀' + jy.currentMD.zh + '大運有利 + 八字大運' + (curBaziDy ? curBaziDy.level : '') + '，雙系統確認目前是好時機',
        weight: 3
      });
    } else if (!jyDashaGood && !baziDyGood) {
      agreements++;
      signals.push({
        type: 'timing_agree_neg',
        zh: '⚠️ 時間軸一致偏弱：吠陀大運能量不足 + 八字大運也偏弱，目前宜穩健不宜冒進',
        weight: -3
      });
    } else {
      disagreements++;
      if (jyDashaGood) {
        signals.push({
          type: 'timing_disagree',
          zh: '🔄 時間軸分歧：吠陀大運看好但八字大運偏弱 → 有潛力但需要更多準備',
          weight: 0
        });
      } else {
        signals.push({
          type: 'timing_disagree',
          zh: '🔄 時間軸分歧：八字大運較好但吠陀大運偏弱 → 機會存在但執行力需加強',
          weight: 0
        });
      }
    }
  }
  
  // ── 2. Personality Comparison: Lagna vs Bazi Ri-Yuan ──
  if (jy.lagna && bazi) {
    var lagnaEl = JY_RASHI[jy.lagna.idx].el;
    var baziEl = bazi.dmEl;
    var elMap = { 'Fire': '火', 'Earth': '土', 'Air': '金', 'Water': '水' };
    // Simplified element mapping (Vedic → Chinese)
    // Fire↔火, Earth↔土, Air≈金(metal/wind), Water↔水
    var jyEl = elMap[lagnaEl] || '';
    if (jyEl === baziEl) {
      agreements++;
      signals.push({
        type: 'personality_agree',
        zh: '✅ 性格特質一致：吠陀上升' + jy.lagnaSign + '(' + lagnaEl + ') 與八字日主' + bazi.dm + '(' + baziEl + ')同屬' + baziEl + '行，兩套系統看到的你一致',
        weight: 2
      });
    } else {
      // Not necessarily disagreement — different systems focus on different aspects
      signals.push({
        type: 'personality_complement',
        zh: '🔗 性格互補面：吠陀看你' + lagnaEl + '屬性（' + (jy.lagnaSign || JY_RASHI[jy.lagna.idx].zh) + '座），八字看你' + baziEl + '行（' + bazi.dm + '），呈現你不同面向',
        weight: 1
      });
    }
  }
  
  // ── 3. Strength Comparison: Shadbala vs Bazi Body Strength ──
  if (jy.shadbala && bazi) {
    var lagnaLord = JY_RASHI[jy.lagna.idx].lord;
    var llShadbala = jy.shadbala[lagnaLord];
    var jyStrong = llShadbala && llShadbala.ratio >= 1.0;
    var baziStrong = bazi.strong;
    
    if (jyStrong && baziStrong) {
      agreements++;
      signals.push({
        type: 'strength_agree_strong',
        zh: '✅ 能量充足確認：吠陀命宮主力量足夠 + 八字身強，你的基礎能量穩定，適合積極行動',
        weight: 2
      });
    } else if (!jyStrong && !baziStrong) {
      agreements++;
      signals.push({
        type: 'strength_agree_weak',
        zh: '⚠️ 能量偏弱確認：吠陀命宮主力量不足 + 八字身弱，需要借助外力（貴人、水晶、時機），不宜單打獨鬥',
        weight: -2
      });
    } else {
      disagreements++;
      signals.push({
        type: 'strength_disagree',
        zh: '🔄 能量評估分歧：' + (jyStrong ? '吠陀看你偏強但八字偏弱' : '八字看你偏強但吠陀偏弱') + ' → 某些面向有力某些需要補強',
        weight: 0
      });
    }
  }
  
  // ── 4. Relationship/Marriage Comparison (if type = love) ──
  if (type === 'love') {
    // Jyotish: 7th lord + Venus + D9
    var lord7 = JY_RASHI[(jy.lagna.idx + 6) % 12].lord;
    var l7p = jy.planets[lord7];
    var jyLoveGood = l7p && (l7p.dignity === 'exalted' || l7p.dignity === 'own' || l7p.dignity === 'friend') && ![6,8,12].includes(l7p.bhava);
    
    // Bazi: peach blossom stars
    var baziLoveGood = bazi.shensha && (bazi.shensha.includes('桃花') || bazi.shensha.includes('紅鸞'));
    
    // Ziwei: 夫妻宮
    var zwLoveGood = false;
    if (ziwei && ziwei.palaces) {
      var fqPalace = ziwei.palaces.find(function(p) { return p.name === '夫妻'; });
      if (fqPalace) {
        var majorStars = fqPalace.stars.filter(function(s) { return s.type === 'major'; });
        zwLoveGood = majorStars.some(function(s) { return ['天府','太陰','天相','天梁','天同'].includes(s.name); });
      }
    }
    
    var lovePosCount = (jyLoveGood ? 1 : 0) + (baziLoveGood ? 1 : 0) + (zwLoveGood ? 1 : 0);
    if (lovePosCount >= 2) {
      signals.push({
        type: 'love_multi_pos',
        zh: '✅ 感情條件多系統認證：' + (jyLoveGood ? '吠陀配偶宮佳' : '') + (baziLoveGood ? ' 八字有桃花星' : '') + (zwLoveGood ? ' 紫微夫妻宮有利' : '') + '，感情基礎良好',
        weight: 3
      });
    } else if (lovePosCount === 0) {
      signals.push({
        type: 'love_multi_neg',
        zh: '⚠️ 感情需多用心：三套系統都提示感情面需要更多經營，不代表沒有緣分但要主動付出',
        weight: -2
      });
    }
  }
  
  // ── 5. Career Comparison (if type = career) ──
  if (type === 'career') {
    var lord10 = JY_RASHI[(jy.lagna.idx + 9) % 12].lord;
    var l10p = jy.planets[lord10];
    var jyCareerGood = l10p && (l10p.dignity === 'exalted' || l10p.dignity === 'own') && [1,4,7,10,5,9].includes(l10p.bhava);
    
    var baziCareerGood = bazi && bazi.strong && bazi.fav;
    
    var zwCareerGood = false;
    if (ziwei && ziwei.palaces) {
      var sgyPalace = ziwei.palaces.find(function(p) { return p.name === '事業' || p.name === '官祿'; });
      if (sgyPalace) {
        var sm = sgyPalace.stars.filter(function(s) { return s.type === 'major'; });
        zwCareerGood = sm.some(function(s) { return ['紫微','天府','太陽','武曲','天相'].includes(s.name); });
      }
    }
    
    var careerPosCount = (jyCareerGood ? 1 : 0) + (baziCareerGood ? 1 : 0) + (zwCareerGood ? 1 : 0);
    if (careerPosCount >= 2) {
      signals.push({
        type: 'career_multi_pos',
        zh: '✅ 事業潛力多系統確認，職涯發展有底氣',
        weight: 3
      });
    }
  }
  
  // ── 6. Transit + Bazi Liuyear Agreement ──
  // Compare Jyotish transit Saturn/Jupiter position with Bazi current year analysis
  try {
    var transits = jyCurrentTransits();
    var jupTransitBhava = ((transits.Jupiter.rashiIdx - jy.lagna.idx + 12) % 12) + 1;
    var satTransitBhava = ((transits.Saturn.rashiIdx - jy.lagna.idx + 12) % 12) + 1;
    
    var jupGoodTransit = [1,2,5,7,9,11].includes(jupTransitBhava);
    var satGoodTransit = [3,6,11].includes(satTransitBhava);
    
    if (jupGoodTransit) {
      signals.push({
        type: 'transit_jup_good',
        zh: '🪐 木星目前行運第' + jupTransitBhava + '宮（' + JY_BHAVA[jupTransitBhava-1].zh + '），帶來擴張與祝福',
        weight: 2
      });
    }
    if (!satGoodTransit && [1,4,7,8,10,12].includes(satTransitBhava)) {
      signals.push({
        type: 'transit_sat_challenge',
        zh: '🪐 土星目前行運第' + satTransitBhava + '宮（' + JY_BHAVA[satTransitBhava-1].zh + '），帶來考驗但也帶來成長',
        weight: -1
      });
    }
  } catch(e) { /* transit calc failed, skip */ }
  
  // ── Summary ──
  var totalWeight = signals.reduce(function(a, s) { return a + s.weight; }, 0);
  var consensusLevel = agreements > disagreements ? '高度一致' : agreements === disagreements ? '部分一致' : '分歧較多';
  
  return {
    signals: signals,
    agreements: agreements,
    disagreements: disagreements,
    totalWeight: totalWeight,
    consensus: consensusLevel,
    summary: signals.length > 0 ? signals.map(function(s) { return s.zh; }).join('\n') : '交叉驗證資料不足'
  };
}

// ── Remedy Suggestions based on Jyotish ──
function jyRemedySuggestions(jy, type) {
  if (!jy) return [];
  var remedies = [];
  var fn = jy.functionalNature;
  var es = jy.effectiveStrength;
  var aff = jy.afflictions;
  var dw = jy.dashaWeights;
  
  if(!fn || !es) return remedies; // engines not available
  
  var gemMap = {
    Sun:     { gem:'紅寶石/太陽石', day:'週日', mantra:'Om Suryaya Namaha' },
    Moon:    { gem:'珍珠/月光石', day:'週一', mantra:'Om Chandraya Namaha' },
    Mars:    { gem:'紅珊瑚/紅碧璽', day:'週二', mantra:'Om Mangalaya Namaha' },
    Mercury: { gem:'翡翠/綠碧璽', day:'週三', mantra:'Om Budhaya Namaha' },
    Jupiter: { gem:'黃色藍寶石/黃水晶', day:'週四', mantra:'Om Gurave Namaha' },
    Venus:   { gem:'鑽石/白水晶', day:'週五', mantra:'Om Shukraya Namaha' },
    Saturn:  { gem:'藍寶石/黑碧璽', day:'週六', mantra:'Om Shanaye Namaha' }
  };
  
  var candidates = [];
  
  ['Sun','Moon','Mars','Mercury','Jupiter','Venus','Saturn'].forEach(function(p) {
    var fnP = fn[p];
    var esP = es[p];
    if(!fnP || !esP) return;
    
    // === CORE RULE: Only recommend strengthening FUNCTIONAL BENEFICS ===
    // Strengthening a functional malefic = DANGER
    if(fnP.dangerToStrengthen){
      // Do NOT recommend this planet's gemstone
      return;
    }
    
    // Priority scoring
    var priority = 0;
    
    // 1. Functional nature weight
    if(fnP.isYogaKaraka) priority += 30;
    else if(fnP.type === 'benefic') priority += 20;
    else if(fnP.type === 'mildBenefic') priority += 10;
    else if(fnP.type === 'neutral') priority += 0;
    // malefic/mildMalefic already filtered out
    
    // 2. Weakness weight (weaker = more priority to strengthen)
    if(esP.effective < 0.7) priority += 25;
    else if(esP.effective < 1.0) priority += 15;
    else if(esP.effective < 1.2) priority += 5;
    
    // 3. Dasha weight (current running planet gets boost)
    var dwP = dw[p] || 1.0;
    if(dwP >= 1.5) priority += 20; // 主運星
    else if(dwP >= 1.2) priority += 10; // 副運星
    
    // 4. Affliction penalty (highly afflicted benefic = urgent to help)
    var affP = aff && aff[p] ? aff[p] : null;
    if(affP && affP.score >= 15) priority += 10;
    
    // Only recommend if there's a real reason
    if(priority <= 10 && esP.effective >= 1.2) return; // strong enough, no need
    
    var reason = '';
    // Build reason string
    if(fnP.isYogaKaraka) reason += '你命盤的最大吉星（瑜伽卡拉卡）';
    else if(fnP.type === 'benefic') reason += '你命盤的功能吉星';
    
    if(dwP >= 1.5) reason += (reason?'，':'') + '目前正在主運期間';
    else if(dwP >= 1.2) reason += (reason?'，':'') + '目前是副運星';
    
    if(esP.effective < 0.7) reason += (reason?'，':'') + '有效力量虛弱（'+esP.effective+'）需要補強';
    else if(esP.effective < 1.0) reason += (reason?'，':'') + '有效力量偏弱（'+esP.effective+'）';
    
    if(affP && affP.score >= 15) reason += (reason?'，':'') + '受到較重的刑沖影響';
    
    if(!reason) reason = JY_PLANETS[p].zh + '是吉星但力量可以更強';
    
    candidates.push({
      planet: p,
      zh: JY_PLANETS[p].zh,
      priority: priority,
      reason: reason,
      gem: gemMap[p].gem,
      mantra: gemMap[p].mantra,
      day: gemMap[p].day,
      fnLabel: fnP.label,
      effective: esP.effective,
      dangerIfStrengthened: false
    });
  });
  
  // Sort by priority descending
  candidates.sort(function(a,b){ return b.priority - a.priority; });
  
  // Take top 3
  remedies = candidates.slice(0, 3);
  
  // Add WARNING for functional malefics that user might mistakenly want to strengthen
  ['Sun','Moon','Mars','Mercury','Jupiter','Venus','Saturn'].forEach(function(p){
    var fnP = fn[p];
    var esP = es[p];
    if(!fnP || !esP) return;
    if(fnP.dangerToStrengthen && esP.shadbala < 0.8){
      remedies.push({
        planet: p,
        zh: JY_PLANETS[p].zh,
        priority: -1,
        reason: '⚠ ' + JY_PLANETS[p].zh + '雖然偏弱，但它是你命盤的功能凶星（管' + fnP.houses.map(function(h){return '第'+h+'宮';}).join('、') + '），補強反而會放大負面影響',
        gem: '❌ 不建議佩戴 ' + (gemMap[p]?gemMap[p].gem:''),
        mantra: '',
        day: '',
        fnLabel: fnP.label,
        effective: esP.effective,
        dangerIfStrengthened: true
      });
    }
  });
  
  return remedies;
}


